 using System.Reflection;

 public class EnumValidator<T, TProperty> : PropertyValidator<T, TProperty>, IEnumValidator {
@@ -37,11 +38,54 @@ public class EnumValidator<T, TProperty> : PropertyValidator<T, TProperty>, IEnu

 		if (!underlyingEnumType.IsEnum) return false;

+		bool valid;
 		if (underlyingEnumType.GetCustomAttribute<FlagsAttribute>() != null) {
-			return IsFlagsEnumDefined(underlyingEnumType, value);
+			valid = IsFlagsEnumDefined(underlyingEnumType, value);
+		}
+		else {
+			valid = Enum.IsDefined(underlyingEnumType, value);
+		}
+
+		if (!valid) {
+			var suggestion = FindClosestMatch(underlyingEnumType, value?.ToString());
+			context.MessageFormatter.AppendArgument("SuggestionMessage",
+				suggestion != null ? $" Did you mean '{suggestion}'?" : string.Empty);
 		}

-		return Enum.IsDefined(underlyingEnumType, value);
+		return valid;
+	}
+
+	private static string FindClosestMatch(Type enumType, string input) {
+		if (string.IsNullOrEmpty(input)) return null;
+		var names = Enum.GetNames(enumType);
+		string best = null;
+		int bestDist = int.MaxValue;
+		foreach (var name in names) {
+			int dist = LevenshteinDistance(input, name);
+			if (dist < bestDist) {
+				bestDist = dist;
+				best = name;
+			}
+		}
+		int threshold = Math.Max(3, input.Length / 2);
+		return bestDist <= threshold ? best : null;
+	}
+
+	private static int LevenshteinDistance(string s, string t) {
+		int n = s.Length, m = t.Length;
+		if (n == 0) return m;
+		if (m == 0) return n;
+		var d = new int[n + 1, m + 1];
+		for (int i = 0; i <= n; i++) d[i, 0] = i;
+		for (int j = 0; j <= m; j++) d[0, j] = j;
+		for (int i = 1; i <= n; i++) {
+			for (int j = 1; j <= m; j++) {
+				int cost = s[i - 1] == t[j - 1] ? 0 : 1;
+				d[i, j] = Math.Min(Math.Min(d[i - 1, j] + 1, d[i, j - 1] + 1), d[i - 1, j - 1] + cost);
+			}
+		}
+		return d[n, m];
+	}
